import{_ as t,o as s,c as o,a6 as a}from"./chunks/framework.CG5ubMb2.js";const h=JSON.parse('{"title":"Mocks","description":"Fake methods with pre-programmed behavior and expectations. Fails tests if not used as expected.","frontmatter":{"title":"Mocks","description":"Fake methods with pre-programmed behavior and expectations. Fails tests if not used as expected."},"headers":[],"relativePath":"concepts/mocks/index.md","filePath":"concepts/mocks/index.md"}'),i={name:"concepts/mocks/index.md"};function n(r,e,c,l,d,p){return s(),o("div",null,[...e[0]||(e[0]=[a('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /concepts/mocks.md for this page in Markdown format</div><h1 id="mocks" tabindex="-1">Mocks <a class="header-anchor" href="#mocks" aria-label="Permalink to “Mocks”">​</a></h1><h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to “Introduction”">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Consider Using Fakes Instead</p><p>Mocks are powerful but easy to overuse. Consider using <a href="/concepts/fakes/">fakes</a> with explicit assertions instead. Fakes provide simpler behavior replacement without coupling tests to implementation details. Reserve mocks for cases where upfront expectations truly clarify test intent.</p></div><p>Mocks (and expectations) are fake methods (like <a href="/concepts/spies/">spies</a>) with pre-programmed behavior (like <a href="/concepts/stubs/">stubs</a>) as well as <strong>pre-programmed expectations</strong>.</p><p>A mock will fail your test if it is not used as expected.</p><h2 id="when-to-use-mocks" tabindex="-1">When to use mocks? <a class="header-anchor" href="#when-to-use-mocks" aria-label="Permalink to “When to use mocks?”">​</a></h2><p>Mocks should only be used for the <em>method under test</em>. In every unit test, there should be one unit under test.</p><p>If you want to control how your unit is being used and like stating expectations upfront (as opposed to asserting after the fact), use a mock.</p><h2 id="when-to-not-use-mocks" tabindex="-1">When to <strong>not</strong> use mocks? <a class="header-anchor" href="#when-to-not-use-mocks" aria-label="Permalink to “When to not use mocks?”">​</a></h2><p>Mocks come with built-in expectations that may fail your test.</p><p>Thus, they enforce implementation details. The rule of thumb is: if you wouldn&#39;t add an assertion for some specific call, don&#39;t mock it. Use a stub instead.</p><p>In general you should have <strong>no more than one</strong> mock (possibly with several expectations) in a single test.</p><p><a href="./api/expectations">Expectations</a> implement both the <a href="/concepts/spies/">spies</a> and <a href="/concepts/stubs/">stubs</a> APIs.</p><h2 id="mocks-vs-stubs-vs-fakes" tabindex="-1">Mocks vs Stubs vs Fakes <a class="header-anchor" href="#mocks-vs-stubs-vs-fakes" aria-label="Permalink to “Mocks vs Stubs vs Fakes”">​</a></h2><p><strong>Use mocks when:</strong></p><ul><li>You want to declare expectations upfront (before acting)</li><li>You need to verify interactions immediately upon use</li><li>The expectation itself clarifies the test&#39;s intent</li></ul><p><strong>Use <a href="/concepts/stubs/">stubs</a> when:</strong></p><ul><li>You need call-specific behavior (<code>onCall()</code>, <code>onFirstCall()</code>)</li><li>You need argument-based behavior (<code>withArgs()</code>)</li><li>You&#39;re controlling behavior but don&#39;t care about verification</li></ul><p><strong>Use <a href="/concepts/fakes/">fakes</a> when:</strong></p><ul><li>You need simple behavior replacement (recommended for most cases)</li><li>You want immutable, predictable test doubles</li><li>You prefer explicit assertions over built-in expectations</li></ul>',21)])])}const m=t(i,[["render",n]]);export{h as __pageData,m as default};
